import React, { useRef } from "react";
import "./GithubRepoCard.css";
import { Fade } from "react-reveal";
import toast from "react-hot-toast";

export default function GithubRepoCard({ repo, theme, onTagClick, activeTag }) {
  const cardRef = useRef(null);

  // Tilt effect on mouse move
  const handleMouseMove = (e) => {
    const card = cardRef.current;
    if (!card) return;
    const rect = card.getBoundingClientRect();
    const x = e.clientX - rect.left;
    const y = e.clientY - rect.top;
    const centerX = rect.width / 2;
    const centerY = rect.height / 2;
    const rotateX = ((y - centerY) / centerY) * -4;
    const rotateY = ((x - centerX) / centerX) * 4;
    card.style.transform = `perspective(800px) rotateX(${rotateX}deg) rotateY(${rotateY}deg) translateY(-6px) scale(1.01)`;
  };

  const handleMouseLeave = () => {
    const card = cardRef.current;
    if (!card) return;
    card.style.transform = "";
  };

  const isValidUrl = (url) => url && url.trim() !== "";
  const hasLogo = isValidUrl(repo?.project_logo);

  const handleCopy = async (url) => {
    if (!url) {
      toast.error("No link to copy!");
      return;
    }
    try {
      if (navigator.clipboard) {
        await navigator.clipboard.writeText(url);
      } else {
        const textarea = document.createElement("textarea");
        textarea.value = url;
        textarea.style.position = "fixed";
        textarea.style.opacity = "0";
        document.body.appendChild(textarea);
        textarea.select();
        document.execCommand("copy");
        document.body.removeChild(textarea);
      }
      toast.success("Link copied!");
    } catch (err) {
      console.error("Copy failed:", err);
      toast.error("Failed to copy link");
    }
  };

  const renderLinkItem = (url, iconClass, bgColor, ariaLabel) => {
    if (!isValidUrl(url)) return null;
    return (
      <li style={{ "--bg": bgColor }}>
        <a
          href={url}
          target="_blank"
          rel="noopener noreferrer"
          aria-label={`${repo?.project_name} — ${ariaLabel}`}
        >
          <i className={iconClass + " store-icon"} aria-hidden="true"></i>
        </a>
        <button
          className="copy-btn-mobile"
          style={{ fontSize: 10, fontWeight: "bold" }}
          onClick={() => handleCopy(url)}
          aria-label={`Copy ${ariaLabel} for ${repo?.project_name}`}
        >
          <i
            className="fa-solid fa-link link-icon"
            style={{ fontSize: 10 }}
            aria-hidden="true"
          ></i>{" "}
          Copy link
        </button>
      </li>
    );
  };

  // Deterministic gradient from project name — 10 curated palettes
  const GRADIENTS = [
    "135deg, #667eea 0%, #764ba2 100%",
    "135deg, #f093fb 0%, #f5576c 100%",
    "135deg, #4facfe 0%, #00f2fe 100%",
    "135deg, #43e97b 0%, #38f9d7 100%",
    "135deg, #fa709a 0%, #fee140 100%",
    "135deg, #a18cd1 0%, #fbc2eb 100%",
    "135deg, #fda085 0%, #f6d365 100%",
    "135deg, #0e6ba8 0%, #a6e1fa 100%",
    "135deg, #30cfd0 0%, #330867 100%",
    "135deg, #f77062 0%, #fe5196 100%",
  ];
  const gradientIndex =
    (repo?.project_name || "")
      .split("")
      .reduce((acc, ch) => acc + ch.charCodeAt(0), 0) % GRADIENTS.length;
  const bannerGradient = `linear-gradient(${GRADIENTS[gradientIndex]})`;

  return (
    <div
      className="repo-card-div"
      ref={cardRef}
      onMouseMove={handleMouseMove}
      onMouseLeave={handleMouseLeave}
      style={{ backgroundColor: theme.whiteBG }}
    >
      <Fade bottom duration={2000} distance="40px">
        <div key={repo?.id}>
          <div
            className="repo-gradient-banner"
            style={{ background: bannerGradient }}
          >
            <div className="repo-gradient-banner-top">
              {hasLogo && (
                <img
                  src={repo.project_logo}
                  alt={`${repo?.project_name || "App"} logo`}
                  className="repo-gradient-banner-logo"
                  loading="lazy"
                />
              )}
              <p className="repo-gradient-banner-name">
                {repo?.project_name || ""}
              </p>
            </div>
            {repo?.project_category && (
              <span className="repo-gradient-banner-category">
                {repo.project_category}
              </span>
            )}
          </div>

          {repo?.project_description && (
            <p
              className="repo-description"
              style={{ color: theme.secondaryText }}
            >
              {repo.project_description}
            </p>
          )}

          <div className="repo-chip">
            {repo?.project_tags?.map((tag, idx) => (
              <button
                key={idx}
                className={`chip${activeTag === tag ? " chip-active" : ""}`}
                onClick={() => onTagClick?.(tag)}
                aria-label={`Filter by tag: ${tag}`}
                aria-pressed={activeTag === tag}
                style={
                  activeTag === tag
                    ? { backgroundColor: theme.imageHighlight, color: "#fff" }
                    : {}
                }
              >
                {tag}
              </button>
            ))}
          </div>

          <div className="repo-stats">
            <ul className="social">
              {renderLinkItem(
                repo?.appstore_url,
                "fa-brands fa-apple",
                "#1D9BF0",
                "App Store",
              )}
              {renderLinkItem(
                repo?.playstore_url,
                "fa-brands fa-google-play",
                "#3DDC84",
                "Play Store",
              )}
              {renderLinkItem(
                repo?.web_url,
                "fa-solid fa-globe",
                "#4285F4",
                "Website",
              )}
            </ul>
          </div>
        </div>
      </Fade>
    </div>
  );
}
